import{_ as r,M as t,p as d,q as c,R as e,t as n,N as o,a1 as h}from"./framework-5866ffd3.js";const l={},s=h('<h1 id="node-和-npm" tabindex="-1"><a class="header-anchor" href="#node-和-npm" aria-hidden="true">#</a> Node 和 NPM</h1><h2 id="它是什么" tabindex="-1"><a class="header-anchor" href="#它是什么" aria-hidden="true">#</a> 它是什么？</h2><p>Node 是一个 JavaScript 运行时环境。</p><p>NPM 是一个 Node 包管理器。</p><h2 id="为什么需要它" tabindex="-1"><a class="header-anchor" href="#为什么需要它" aria-hidden="true">#</a> 为什么需要它？</h2><p>作为前端开发人员，如果你想进行服务端开发，使用 Node 的学习成本是比较低的。当然，作为前端开发人员，我们通常把它作为一个项目构建工具，比如 Vue 脚手架、React 脚手架都需要基于 Node 来运行。</p><p>NPM 可以为我们提供依赖管理、脚本运行和程序打包等功能，且 NPM 上托管着大量的第三方包和插件，方便我们进行项目快速开发。</p><h2 id="如何使用它" tabindex="-1"><a class="header-anchor" href="#如何使用它" aria-hidden="true">#</a> 如何使用它？</h2><p>由于在上一节我们已经安装了 NVM，并且使用 NVM 安装了 Node 和 NPM，如果你启动 cmd 并且执行 <code>node -v</code> 和 <code>npm -v</code> 均能输出对应版本号，那么就说明安装成功了。</p><h2 id="npm-全局包" tabindex="-1"><a class="header-anchor" href="#npm-全局包" aria-hidden="true">#</a> NPM 全局包</h2><p>请使用 <code>npm i -g &lt;packageName&gt;</code> （<code>&lt;packageName&gt;</code> 就是包名）命令安装以下推荐的全局包：</p><hr>',12),p={href:"https://cli.vuejs.org/zh/",target:"_blank",rel:"noopener noreferrer"},i=e("hr",null,null,-1),_={href:"https://www.npmjs.com/package/nrm",target:"_blank",rel:"noopener noreferrer"},u=e("hr",null,null,-1),m={href:"https://pnpm.io/zh/installation",target:"_blank",rel:"noopener noreferrer"},N=e("hr",null,null,-1),f=e("p",null,[n("你可以使用 "),e("code",null,"npm ls -g --depth=0"),n(" 查看目前已经安装的全局包。")],-1);function M(g,x){const a=t("ExternalLinkIcon");return d(),c("div",null,[s,e("p",null,[e("a",p,[n("@vue/cli"),o(a)]),n("：Vue 项目开发的脚手架工具。在 Vue3 项目中，我们已经不再需要它，但是如果要构建一个 Vue2 项目，我们依然选用它。")]),i,e("p",null,[e("a",_,[n("nrm"),o(a)]),n("：NPM 镜像源管理工具，允许你在 NPM 镜像源间快速切换。")]),u,e("p",null,[e("a",m,[n("pnpm"),o(a)]),n("：相比于 NPM，PNPM 是速度更快且更节省磁盘空间的包管理器。")]),N,f])}const k=r(l,[["render",M],["__file","node-and-npm.html.vue"]]);export{k as default};
